/// <summary>
///  QualitySpecificationGroup, Binay 21, Jan ,2021
/// </summary>
/// <returns></returns>
public boolean isValidEntry()
{
    ETG_PostPackingQualityGrp    postPackingQualityGrp;
    boolean     ret;

    select firstonly  postPackingQualityGrp
        where postPackingQualityGrp.RecId != this.RecId
        && postPackingQualityGrp.SalesId == this.SalesId
        && postPackingQualityGrp.Invalid == NoYes::No
        && postPackingQualityGrp.ResultValue > 0;

    if (postPackingQualityGrp.RecId)
    {
        ret = false;

    }
    else
    {
        ret = false;
    }

    return ret;

}

    /// <summary>
    ///
    /// </summary>
    /// <param name = "_fieldIdToCheck"></param>
    /// <returns></returns>
    public boolean validateField(FieldId _fieldIdToCheck)
    {
        boolean                      ret;
        ETG_PostPackingQualityGrp    postPackingQualityGrp;
        ret = super(_fieldIdToCheck);

        switch(_fieldIdToCheck)
        {
            case fieldNum(ETG_PostPackingQualityGrp, MaxRange) :

                select firstonly RecId  from postPackingQualityGrp
                    where postPackingQualityGrp.RecId != this.RecId
                        && postPackingQualityGrp.InventTransId   == this.InventTransId
                        && postPackingQualityGrp.GroupID         == this.GroupID
                        && postPackingQualityGrp.MeasurementType == this.MeasurementType
                        &&  postPackingQualityGrp.MinRange <= this.MaxRange
                        && postPackingQualityGrp.MaxRange >= this.MaxRange  ;

                if (postPackingQualityGrp)
                {
                    ret = false;
                    Error('This min - max range was already exist');
                }

                if ( this.MaxRange < this.MinRange)
                {
                    ret = false;
                    Error('Max value should be greater than min value');
                }

                break;

            case fieldNum(ETG_PostPackingQualityGrp, MinRange) :

                select firstonly RecId  from postPackingQualityGrp
                    where postPackingQualityGrp.RecId != this.RecId
                        && postPackingQualityGrp.InventTransId   == this.InventTransId
                        && postPackingQualityGrp.GroupID         == this.GroupID
                        && postPackingQualityGrp.MeasurementType == this.MeasurementType
                        &&  postPackingQualityGrp.MinRange <= this.MinRange
                        && postPackingQualityGrp.MaxRange >= this.MinRange  ;

                if (postPackingQualityGrp)
                {
                    ret = false;
                    Error('This min - max range was already exist');
                }

                if ( this.MaxRange < this.MinRange)
                {
                    ret = false;
                    Error('Max value should be greater than min value');
                }

                break;

           /* case fieldNum(ETG_PostPackingQualityGrp, ResultValue) :

                if ( this.ResultValue < this.MinRange || this.ResultValue > this.MaxRange)
                {
                    ret = false;
                    Error('Result value should be with in min - max range');
                }

                break;*/

        }



        return ret;
    }

